padding: 0 15px;
border-right: 1px solid #666;
}

.topbar-nav ul&gt;li:first-child a {
padding-left: 0;
}

.topbar-nav ul&gt;li:last-child a{
border-style: none;
padding-right: 0;
}
</code></pre>

